import Foundation

struct VerseOfTheDayEntry {
    let dayOfYear: Int
    let bookName: String
    let chapter: Int
    let verse: Int
    let text: String
}

// 366 entries — one per day of the year (day 1 = Jan 1, day 366 = Dec 31 in leap year).
// Seasonal passages are anchored to the calendar; the rest are spread through well-known
// verses from across the Bible in a varied order.
let verseOfTheDayVerses: [VerseOfTheDayEntry] = [
